import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

function UploadBills({ employee }) {
  const navigate = useNavigate();
  const apiBase = "https://prasa-app-yde3.onrender.com";

  const empId = employee?.empId || employee?.empld;

  const [files, setFiles] = useState([]);
  const [billList, setBillList] = useState([]);

  useEffect(() => {
    fetchBills();
  }, []);

  const fetchBills = async () => {
    try {
      const res = await fetch(
        `${apiBase}/bills?empId=${encodeURIComponent(empId)}`
      );
      const data = await res.json();
      setBillList(Array.isArray(data) ? data : []);
    } catch (err) {
      console.error(err);
    }
  };

  const uploadFiles = async () => {
    if (!files.length) return alert("Please select a file");

    const fd = new FormData();
    fd.append("empId", empId);

    for (let f of files) fd.append("files", f);

    await fetch(`${apiBase}/bills/upload`, { method: "POST", body: fd });

    alert("Bills uploaded!");
    fetchBills();
  };

  const deleteBill = async (id) => {
    await fetch(`${apiBase}/bills/delete/${id}`, { method: "DELETE" });
    fetchBills();
  };

  return (
    <div style={outer}>
      <div style={card}>
        <div style={headerRow}>
          <button onClick={() => navigate("/tools")} style={backBtn}>←</button>
          <h2 style={title}>Upload Bills</h2>
        </div>

        <p style={empInfo}>
          Employee: {employee.empName || employee.name} • {empId}
        </p>

        <div style={uploadBox}>
          <input type="file" multiple onChange={(e) => setFiles(e.target.files)} />
          <button onClick={uploadFiles} style={uploadBtn}>Upload</button>
        </div>

        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>File</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {billList.length === 0 ? (
              <tr>
                <td colSpan="3" style={noData}>No bills uploaded.</td>
              </tr>
            ) : (
              billList.map((b) => (
                <tr key={b.id}>
                  <td>{b.uploaded_at?.substring(0, 10)}</td>
                  <td>{b.file_name}</td>
                  <td>
                    <button onClick={() => deleteBill(b.id)} style={deleteBtn}>
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>

      </div>
    </div>
  );
}

export default UploadBills;

/* ---------- STYLES ---------- */
const outer = { width:"100%", minHeight:"100vh", background:"#f5faf7", padding:"20px" };
const card = { background:"#fff", padding:"20px", borderRadius:"12px", boxShadow:"0 2px 10px rgba(0,0,0,0.05)" };
const headerRow = { display:"flex", alignItems:"center", gap:"10px" };
const backBtn = { background:"transparent", border:"none", fontSize:"20px", cursor:"pointer", color:"#0f9d58" };
const title = { fontSize:"22px", fontWeight:"600", color:"#0f9d58" };
const empInfo = { color:"#666", marginTop:"-5px" };
const uploadBox = { marginTop:"15px", display:"flex", gap:"15px", alignItems:"center" };
const uploadBtn = { background:"#0f9d58", color:"#fff", border:"none", padding:"8px 16px", borderRadius:"6px", cursor:"pointer" };
const table = { width:"100%", marginTop:"20px", borderCollapse:"collapse" };
const deleteBtn = { background:"#d9534f", color:"#fff", border:"none", padding:"6px 12px", borderRadius:"5px", cursor:"pointer" };
const noData = { textAlign:"center", padding:"20px", color:"#777" };
